const b = ($input.first().json || {}).body || $input.first().json || {};
let ip = String(b.ip||'').trim();
let agent = String(b.agent||'001').trim();
let delay = Number(b.delay||30);
if(isNaN(delay)||delay<1) delay=1;
if(delay>1209600) delay=1209600;            // cap 14 jours
return [{json:{ip, agent, delay}}];

const http=require('http');
const ip=$('Validate').first().json.ip;
if(!ip) return [{json:{ok:false,msg:'ip manquante'}}];
const bp=JSON.stringify({token:'<TOKEN_PONT_A_CONFIGURER>',ip});
const bres=await new Promise((res)=>{const rr=http.request({host:'172.17.0.1',port:5601,path:'/unban',method:'POST',timeout:60000,headers:{'Content-Type':'application/json','Content-Length':Buffer.byteLength(bp)}},x=>{let b='';x.on('data',c=>b+=c);x.on('end',()=>res(b));});rr.on('error',e=>res(JSON.stringify({ok:false,message:e.message})));rr.on('timeout',()=>{rr.destroy();res(JSON.stringify({ok:false,message:'timeout'}));});rr.write(bp);rr.end();});
let j={}; try{j=JSON.parse(bres);}catch(e){}
try{ require('fs').appendFileSync('/home/node/.n8n/soar_bans.jsonl', JSON.stringify({type:'unban',ip,agent:'000,001,002',ts:new Date().toISOString(),source:'auto'})+'\n'); }catch(e){}
return [{json:{ok:!!j.ok, ip, msg:j.message||bres}}];
